import { useState } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {
      setUploadedLogo(URL.createObjectURL(file))
    }
  }

  return (
    <div className="min-h-screen bg-black text-white grid grid-cols-1 lg:grid-cols-2 gap-10 px-6 py-20">


      <div className="bg-[#111] rounded-3xl border border-[#222] p-10 flex items-center justify-center relative overflow-hidden min-h-[850px]">

        <img
          src={selectedColor.image}
          alt="shirt"
          className="w-full max-w-[700px] relative z-10"
        />


        {uploadedLogo && (
          <img
            src={uploadedLogo}
            alt="logo"
            className="absolute z-20 opacity-90 mix-blend-multiply"
            style={{
              width: '220px',
              top: '42%',
              left: '50%',
              transform: 'translate(-50%, -50%)'
            }}
          />
        )}


        <img
          src="/mockups/wrinkle-overlay.png"
          alt="wrinkles"
          className="absolute inset-0 w-full h-full object-cover z-30 opacity-40 mix-blend-overlay pointer-events-none"
        />


        <img
          src="/mockups/texture-overlay.png"
          alt="texture"
          className="absolute inset-0 w-full h-full object-cover z-40 opacity-20 mix-blend-soft-light pointer-events-none"
        />

      </div>


      <div>

        <p className="text-yellow-500 tracking-[0.4em] text-xs uppercase mb-6">
          Premium Apparel Printing
        </p>


        <h1 className="text-6xl font-black mb-6 leading-none">
          {product.name}
        </h1>


        <p className="text-3xl text-yellow-500 mb-12">
          Starting at ${product.price}
        </p>


        <div className="mb-12">

          <h2 className="text-xl mb-6 font-bold">
            Select Color
          </h2>


          <div className="flex gap-4 flex-wrap">

            {product.colors.map(color => (
              <button
                key={color.name}
                onClick={() => setSelectedColor(color)}
                className="w-14 h-14 rounded-full border-4 border-white"
                style={{ backgroundColor: color.hex }}
              />
            ))}

          </div>
        </div>


        <div className="mb-12">

          <h2 className="text-xl mb-6 font-bold">
            Upload Logo
          </h2>


          <input
            type="file"
            accept="image/png,image/jpeg"
            onChange={handleUpload}
            className="w-full bg-[#111] border border-[#222] rounded-2xl p-5"
          />
        </div>


        <div className="mb-12">

          <h2 className="text-xl mb-6 font-bold">
            Sizes
          </h2>


          <div className="flex gap-4 flex-wrap">

            {['S','M','L','XL','2XL','3XL'].map(size => (
              <button
                key={size}
                className="px-8 py-4 border border-[#222] rounded-2xl"
              >
                {size}
              </button>
            ))}

          </div>
        </div>


        <button className="w-full bg-yellow-500 text-black text-xl font-black py-6 rounded-3xl">
          REQUEST QUOTE
        </button>

      </div>
    </div>
  )
}
